def _b64decode(segment: str) -> str:
    padding = '=' * (-len(segment) % 4)
    return base64.urlsafe_b64decode(segment + padding).decode()


def decode_jwt(
    token: str,
    key: str = "",
    algorithms: Optional[List[str]] = None,
    verify_signature: bool = True,
) -> Dict[str, Any]:
    if algorithms is None:
        algorithms = [
            "HS256",
            "HS384",
            "HS512",
            "RS256",
            "RS384",
            "RS512",
            "ES256",
            "ES384",
        ]

    result: Dict[str, Any] = {
        "header": None,
        "payload": None,
        "signature_verified": None,
        "token_valid": None,
        "error": None,
    }

    try:
        header_b64, payload_b64, _ = token.split(".")
    except ValueError:
        result["error"] = "Token must have exactly 3 segments"
        return result

    try:
        result["header"] = json.loads(_b64decode(header_b64))
        result["payload"] = json.loads(_b64decode(payload_b64))
    except Exception as exc:
        result["error"] = f"Base64/JSON decoding error: {exc}"
        return result

    if verify_signature and key:
        try:
            jwt.decode(token, key, algorithms=algorithms)
            result["signature_verified"] = True
            result["token_valid"] = True
        except InvalidTokenError as exc:
            result["signature_verified"] = False
            result["token_valid"] = False
            result["error"] = str(exc)

    return result


